request.query:
prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?task ?taskName ?participant ?participantName
WHERE {
  ?model tai:originalId "3c08e52742754da6a4065fc5787131dc" .
  ?definitions tai:belongsTo ?model .
  ?choreo tai:belongsTo ?definitions .

  ?task tai:belongsTo ?choreo ;
        a bboExt:ChoreographyTask ;
        bbo:name ?taskName .

  ?participant tai:belongsTo ?choreo ;
               a bboExt:Participant ;
               bbo:name ?participantName .

  FILTER(CONTAINS(?participantName, "Paymen tOrg."))
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?taskName
WHERE {
  ?model tai:originalId "3c08e52742754da6a4065fc5787131dc" .
  ?definitions tai:belongsTo ?model .
  ?choreo tai:belongsTo ?definitions .

  ?task tai:belongsTo ?choreo ;
        a bboExt:ChoreographyTask ;
        bbo:name ?taskName ;
        bboExt:initiatingParticipantRef ?partRef .

  ?participant tai:belongsTo ?choreo ;
               a bboExt:Participant ;
               bbo:name "Payment Org." .

  FILTER(STRENDS(STR(?participant), ?partRef))
}
